mapper.select:
SELECT s.store_id id, s.store_name name, s.min_price min,
s.rating_avg avg, s.rating_count sum, s.order_count count,
s.store_pic pic, s.state, s.created_at createdAt
FROM store s join store_category c on s.store_id=c.store_id


        AND s.store_name LIKE CONCAT('%', #{searchText}, '%')


        AND c.category_id = #{categoryId}


ORDER BY s.${sortType} ${sortOrder}
LIMIT #{startIdx}, #{size}

SELECT COUNT(1)
FROM store s
WHERE s.created_at >= #{start}
AND s.created_at < #{end}

select count(1) from store s join store_category c on c.store_id=s.store_id


AND s.store_name LIKE CONCAT('%', #{searchText}, '%')


    AND c.category_id = #{categoryId}
